/**
 * MMS - Metro Mileage Management System
 * Fastify API Server
 *
 * Main entry point for the backend API
 */

import Fastify from 'fastify';
import cors from '@fastify/cors';

// Import route handlers
import { dashboardRoutes } from './routes/dashboard';
import { trainsRoutes } from './routes/trains';
import { depotsRoutes } from './routes/depots';
import { servicesRoutes } from './routes/services';
import { allocationsRoutes } from './routes/allocations';
import { balancingRoutes } from './routes/balancing';
import { simulationRoutes } from './routes/simulation';
import { maintenanceRoutes } from './routes/maintenance';
import { checkDatabaseConnection } from './db/client';

const fastify = Fastify({
  logger: {
    level: process.env.LOG_LEVEL || 'info',
    transport: {
      target: 'pino-pretty',
      options: {
        translateTime: 'HH:MM:ss Z',
        ignore: 'pid,hostname',
      },
    },
  },
});

// Register CORS for frontend access
await fastify.register(cors, {
  origin: ['http://localhost:3000'],
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],
});

// Health check endpoint
fastify.get('/health', async () => {
  const dbConnected = await checkDatabaseConnection();

  return {
    status: dbConnected ? 'ok' : 'degraded',
    timestamp: new Date().toISOString(),
    service: 'mms-api',
    database: dbConnected ? 'connected' : 'disconnected',
  };
});

// Register API routes
await fastify.register(dashboardRoutes, { prefix: '/api/dashboard' });
await fastify.register(trainsRoutes, { prefix: '/api/trains' });
await fastify.register(depotsRoutes, { prefix: '/api/depots' });
await fastify.register(servicesRoutes, { prefix: '/api/services' });
await fastify.register(allocationsRoutes, { prefix: '/api/allocations' });
await fastify.register(balancingRoutes, { prefix: '/api/balancing' });
await fastify.register(simulationRoutes, { prefix: '/api/simulation' });
await fastify.register(maintenanceRoutes, { prefix: '/api/maintenance' });

// Start server
const start = async () => {
  try {
    const port = Number(process.env.PORT) || 4000;
    const host = process.env.HOST || '0.0.0.0';

    await fastify.listen({ port, host });

    console.log(`
╔════════════════════════════════════════════╗
║  MMS API Server                            ║
╠════════════════════════════════════════════╣
║  Status:   Running                         ║
║  Address:  http://${host}:${port}              ║
╚════════════════════════════════════════════╝

Available Endpoints:
  GET  /health                    Health check
  GET  /api/dashboard/summary     Dashboard KPIs
  GET  /api/dashboard/depot-capacity  Depot occupancy
  GET  /api/trains                Train list
  GET  /api/trains/:id            Train details
  GET  /api/trains/:id/history    Mileage history
  GET  /api/depots                Depot list
  GET  /api/services              Service list
  GET  /api/services/pending      Pending allocations
  POST /api/allocations/recommend Get recommendations
  POST /api/allocations           Create allocation
  GET  /api/balancing/distribution Km distribution
  GET  /api/balancing/ranking     Train ranking
  POST /api/simulation/create     Create scenario
  POST /api/simulation/:id/run    Run simulation
`);
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};

start();

