     2→ * MMS - Dashboard Routes
     3→ *
     4→ * Endpoints for dashboard KPIs and overview data
     5→ */
     6→
     7→import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
     8→import { db, schema } from '../db/client';
     9→import { sql, count, avg, and, eq, gte, lte } from 'drizzle-orm';
    10→
    11→export async function dashboardRoutes(fastify: FastifyInstance) {
    12→  // GET /api/dashboard/summary
    13→  fastify.get('/summary', async (request: FastifyRequest, reply: FastifyReply) => {
    14→    try {
    15→      // Count total trains
    16→      const totalResult = await db.select({ value: count() }).from(schema.trains);
    17→      const totalTrains = Number(totalResult[0].value);
    18→
    19→      // Count available (fit) trains
    20→      const availableResult = await db
    21→        .select({ value: count() })
    22→        .from(schema.trains)
    23→        .where(eq(schema.trains.fitnessStatus, 'fit'));
    24→      const availableTrains = Number(availableResult[0].value);
    25→
    26→      // Count in-maintenance
    27→      const inMaintenanceCount = totalTrains - availableTrains;
    28→
    29→      // Calculate km variance
    30→      const kmStats = await db
    31→        .select({
    32→          avgKm: avg(schema.trains.currentKm),
    33→          targetKm: avg(schema.trains.targetKm),
    34→        })
    35→        .from(schema.trains);
    36→
    37→      const avgKm = Number(kmStats[0].avgKm) || 0;
    38→      const targetKm = Number(kmStats[0].targetKm) || avgKm;
    39→
    40→      // Calculate variance percentage based on standard deviation
    41→      const varianceQuery = await db.execute(sql`
    42→        SELECT
    43→          ROUND(STDDEV(current_km) / NULLIF(AVG(current_km), 0) * 100, 1) as variance_percent
    44→        FROM trains
    45→      `);
    46→      const kmVariance = Number((varianceQuery as any)[0]?.variance_percent) || 0;
    47→
    48→      // Determine variance status
    49→      let varianceStatus: 'green' | 'yellow' | 'red';
    50→      if (kmVariance <= 10) varianceStatus = 'green';
    51→      else if (kmVariance <= 20) varianceStatus = 'yellow';
    52→      else varianceStatus = 'red';
    53→
    54→      return {
    55→        totalTrains,
    56→        availableTrains,
    57→        inMaintenanceCount,
    58→        kmVariance,
    59→        varianceStatus,
    60→      };
    61→    } catch (error) {
    62→      request.log.error(error);
    63→      reply.status(500).send({ error: 'Failed to fetch dashboard summary' });
    64→    }
    65→  });
    66→
    67→  // GET /api/dashboard/depot-capacity
    68→  fastify.get('/depot-capacity', async (request: FastifyRequest, reply: FastifyReply) => {
    69→    try {
    70→      const depots = await db.select().from(schema.depots);
    71→
    72→      // For each depot, count trains currently stationed there
    73→      const result = await Promise.all(
    74→        depots.map(async (depot) => {
    75→          const trainCount = await db
    76→            .select({ value: count() })
    77→            .from(schema.trains)
    78→            .where(eq(schema.trains.baseDepotId, depot.id));
    79→
    80→          const currentOccupancy = Number(trainCount[0].value);
    81→          const maxCapacity = depot.capacityTracks || 5;
    82→          const percentUsed = Math.round((currentOccupancy / maxCapacity) * 100);
    83→
    84→          return {
    85→            id: depot.id,
    86→            name: depot.name,
    87→            code: depot.code,
    88→            currentOccupancy,
    89→            maxCapacity,
    90→            percentUsed,
    91→          };
    92→        })
    93→      );
    94→
    95→      return { depots: result };
    96→    } catch (error) {
    97→      request.log.error(error);
    98→      reply.status(500).send({ error: 'Failed to fetch depot capacity' });
    99→    }
   100→  });
   101→
   102→  // GET /api/dashboard/maintenance-alerts
   103→  fastify.get('/maintenance-alerts', async (request: FastifyRequest, reply: FastifyReply) => {
   104→    try {
   105→      const today = new Date();
   106→      const sevenDaysFromNow = new Date(today);
   107→      sevenDaysFromNow.setDate(sevenDaysFromNow.getDate() + 7);
   108→
   109→      const todayStr = today.toISOString().split('T')[0];
   110→      const futureStr = sevenDaysFromNow.toISOString().split('T')[0];
   111→
   112→      // Get upcoming maintenance in next 7 days
   113→      const upcomingMaintenance = await db.query.maintenanceSchedules.findMany({
   114→        where: and(
   115→          gte(schema.maintenanceSchedules.scheduledDate, todayStr),
   116→          lte(schema.maintenanceSchedules.scheduledDate, futureStr),
   117→          eq(schema.maintenanceSchedules.status, 'scheduled')
   118→        ),
   119→        with: {
   120→          train: true,
   121→          depot: true,
   122→        },
   123→        orderBy: (ms, { asc }) => [asc(ms.scheduledDate)],
   124→        limit: 10,
   125→      });
   126→
   127→      // Count by type
   128→      const countByType = {
   129→        PM1: 0,
   130→        PM2: 0,
   131→        HM: 0,
   132→        OVH: 0,
   133→      };
   134→
   135→      upcomingMaintenance.forEach((m) => {
   136→        const type = m.maintenanceType as keyof typeof countByType;
   137→        if (type in countByType) {
   138→          countByType[type]++;
   139→        }
   140→      });
   141→
   142→      // Format alerts list (top 5)
   143→      const alerts = upcomingMaintenance.slice(0, 5).map((m) => ({
   144→        id: m.id,
   145→        trainId: m.train?.trainId || 'Unknown',
   146→        type: m.maintenanceType,
   147→        date: m.scheduledDate,
   148→        depot: m.depot?.name || 'Unknown',
   149→        depotCode: m.depot?.code || '--',
   150→        durationDays: m.durationDays || 1,
   151→      }));
   152→
   153→      return {
   154→        totalUpcoming: upcomingMaintenance.length,
   155→        countByType,
   156→        alerts,
   157→      };
   158→    } catch (error) {
   159→      request.log.error(error);
   160→      reply.status(500).send({ error: 'Failed to fetch maintenance alerts' });
   161→    }
   162→  });
   163→}
