/**
 * MMS - Trains Routes
 *
 * Endpoints for train data and mileage history
 */

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { db, schema } from '../db/client';
import { eq, desc, asc, and, gte, lte, avg } from 'drizzle-orm';

interface TrainQueryParams {
  fleet?: string;
  depot?: string;
  status?: 'fit' | 'unfit';
  limit?: string;
  offset?: string;
}

interface TrainIdParams {
  id: string;
}

export async function trainsRoutes(fastify: FastifyInstance) {
  // GET /api/trains
  fastify.get('/', async (request: FastifyRequest<{ Querystring: TrainQueryParams }>, reply: FastifyReply) => {
    try {
      const { fleet, depot, status, limit = '100', offset = '0' } = request.query;

      // Build query conditions
      const conditions = [];
      if (fleet) conditions.push(eq(schema.trains.fleetId, fleet));
      if (depot) conditions.push(eq(schema.trains.baseDepotId, depot));
      if (status) conditions.push(eq(schema.trains.fitnessStatus, status));

      // Get average km for delta calculation
      const avgResult = await db.select({ value: avg(schema.trains.currentKm) }).from(schema.trains);
      const fleetAverageKm = Number(avgResult[0].value) || 0;

      // Fetch trains with relations
      const trains = await db.query.trains.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        with: {
          fleet: true,
          baseDepot: true,
        },
        limit: Number(limit),
        offset: Number(offset),
        orderBy: [asc(schema.trains.trainId)],
      });

      // Add delta calculations
      const trainsWithDelta = trains.map(train => ({
        ...train,
        deltaFromAverage: train.currentKm - fleetAverageKm,
        deltaPercent: Math.round(((train.currentKm - fleetAverageKm) / fleetAverageKm) * 100),
      }));

      return { trains: trainsWithDelta };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch trains' });
    }
  });

  // GET /api/trains/:id
  fastify.get('/:id', async (request: FastifyRequest<{ Params: TrainIdParams }>, reply: FastifyReply) => {
    try {
      const { id } = request.params;

      const train = await db.query.trains.findFirst({
        where: eq(schema.trains.id, id),
        with: {
          fleet: true,
          baseDepot: true,
          maintenanceSchedules: {
            orderBy: [desc(schema.maintenanceSchedules.scheduledDate)],
            limit: 5,
          },
        },
      });

      if (!train) {
        return reply.status(404).send({ error: 'Train not found' });
      }

      // Get average km for delta
      const avgResult = await db.select({ value: avg(schema.trains.currentKm) }).from(schema.trains);
      const fleetAverageKm = Number(avgResult[0].value) || 0;

      return {
        ...train,
        deltaFromAverage: train.currentKm - fleetAverageKm,
        deltaPercent: Math.round(((train.currentKm - fleetAverageKm) / fleetAverageKm) * 100),
      };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch train' });
    }
  });

  // GET /api/trains/:id/history
  fastify.get('/:id/history', async (request: FastifyRequest<{ Params: TrainIdParams }>, reply: FastifyReply) => {
    try {
      const { id } = request.params;

      const history = await db
        .select()
        .from(schema.mileageHistory)
        .where(eq(schema.mileageHistory.trainId, id))
        .orderBy(asc(schema.mileageHistory.recordedDate));

      return {
        trainId: id,
        history: history.map(h => ({
          date: h.recordedDate,
          km: h.kmValue,
        })),
      };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch train history' });
    }
  });
}

