/**
 * MMS - Depots Routes
 *
 * Endpoints for depot data
 */

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { db, schema } from '../db/client';
import { eq, count } from 'drizzle-orm';

interface DepotIdParams {
  id: string;
}

export async function depotsRoutes(fastify: FastifyInstance) {
  // GET /api/depots
  fastify.get('/', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      const depots = await db.select().from(schema.depots);

      // Enrich with train counts
      const result = await Promise.all(
        depots.map(async (depot) => {
          const trainCount = await db
            .select({ value: count() })
            .from(schema.trains)
            .where(eq(schema.trains.baseDepotId, depot.id));

          return {
            ...depot,
            trainCount: Number(trainCount[0].value),
          };
        })
      );

      return { depots: result };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch depots' });
    }
  });

  // GET /api/depots/:id
  fastify.get('/:id', async (request: FastifyRequest<{ Params: DepotIdParams }>, reply: FastifyReply) => {
    try {
      const { id } = request.params;

      const depot = await db.query.depots.findFirst({
        where: eq(schema.depots.id, id),
      });

      if (!depot) {
        return reply.status(404).send({ error: 'Depot not found' });
      }

      // Get trains at this depot
      const trains = await db
        .select()
        .from(schema.trains)
        .where(eq(schema.trains.baseDepotId, id));

      return {
        ...depot,
        trains,
      };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch depot' });
    }
  });
}

