/**
 * MMS - Services Routes
 *
 * Endpoints for service/route data
 */

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { db, schema } from '../db/client';
import { eq, and, isNull, sql, desc, asc } from 'drizzle-orm';

interface ServiceQueryParams {
  date?: string;
  type?: 'regional' | 'intercity';
}

export async function servicesRoutes(fastify: FastifyInstance) {
  // GET /api/services
  fastify.get('/', async (request: FastifyRequest<{ Querystring: ServiceQueryParams }>, reply: FastifyReply) => {
    try {
      const { type } = request.query;

      const conditions = [];
      if (type) conditions.push(eq(schema.services.serviceType, type));

      const services = await db.query.services.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: [asc(schema.services.departureTime)],
        limit: 100,
      });

      return { services };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch services' });
    }
  });

  // GET /api/services/pending - Services needing allocation
  fastify.get('/pending', async (request: FastifyRequest<{ Querystring: { date?: string } }>, reply: FastifyReply) => {
    try {
      const date = request.query.date || new Date().toISOString().split('T')[0];

      // Find services without allocations for the given date
      const pendingServices = await db.execute(sql`
        SELECT s.*
        FROM services s
        LEFT JOIN allocations a ON s.id = a.service_id AND a.allocation_date = ${date}
        WHERE a.id IS NULL
        ORDER BY s.departure_time ASC
        LIMIT 50
      `);

      return {
        date,
        services: pendingServices as any[],
      };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch pending services' });
    }
  });
}

