/**
 * MMS - Database Client Configuration
 *
 * Uses Drizzle ORM with PostgreSQL
 */

import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import * as schema from './schema';

// Connection string from environment
const connectionString = process.env.DATABASE_URL || 'postgresql://mms:mms@localhost:5432/mms';

// Create postgres connection
const client = postgres(connectionString, {
  max: 10,
  idle_timeout: 20,
});

// Create drizzle instance with schema
export const db = drizzle(client, { schema });

// Export schema for use elsewhere
export { schema };

// Health check function
export async function checkDatabaseConnection(): Promise<boolean> {
  try {
    await client`SELECT 1`;
    return true;
  } catch (error) {
    console.error('Database connection failed:', error);
    return false;
  }
}

import { defineConfig } from 'drizzle-kit';

export default defineConfig({
  dialect: 'postgresql',
  schema: './src/db/schema.ts',
  out: './drizzle',
  dbCredentials: {
    url: process.env.DATABASE_URL || 'postgresql://mms:mms@localhost:5432/mms',
  },
});

/**
 * MMS - Metro Mileage Management System
 * Seed Data Generator
 *
 * Generates realistic demo data for Portuguese railway operations
 * Based on PRD specifications (2025-12-28)
 */

import postgres from 'postgres';

const connectionString = process.env.DATABASE_URL || 'postgresql://mms:mms@localhost:5432/mms';
const sql = postgres(connectionString);

// =============================================================================
// Data Definitions
// =============================================================================

const FLEETS = [
  { name: 'Metro Series 2200', manufacturer: 'Siemens', pm1: 15000, pm2: 45000, hm: 90000 },
  { name: 'Metro Series 2400', manufacturer: 'CAF', pm1: 18000, pm2: 54000, hm: 108000 },
  { name: 'Intercity Series 3400', manufacturer: 'Alstom', pm1: 20000, pm2: 60000, hm: 120000 },
  { name: 'Regional Series 3500', manufacturer: 'Stadler', pm1: 15000, pm2: 45000, hm: 90000 },
  { name: 'Urban Series 4000', manufacturer: 'Bombardier', pm1: 12000, pm2: 36000, hm: 72000 },
];

const DEPOTS = [
  { name: 'Lisboa - Santa Apolónia', code: 'LSA', lat: 38.7139, lon: -9.1227, tracks: 8, manhours: 160 },
  { name: 'Lisboa - Entrecampos', code: 'LEC', lat: 38.7472, lon: -9.1498, tracks: 6, manhours: 120 },
  { name: 'Porto - Campanhã', code: 'PRC', lat: 41.1496, lon: -8.5857, tracks: 10, manhours: 200 },
  { name: 'Porto - São Bento', code: 'PSB', lat: 41.1455, lon: -8.6108, tracks: 4, manhours: 80 },
  { name: 'Coimbra B', code: 'COI', lat: 40.2115, lon: -8.4356, tracks: 5, manhours: 100 },
  { name: 'Braga', code: 'BRG', lat: 41.5454, lon: -8.4265, tracks: 4, manhours: 80 },
  { name: 'Aveiro', code: 'AVE', lat: 40.6405, lon: -8.6538, tracks: 3, manhours: 60 },
  { name: 'Faro', code: 'FAR', lat: 37.0194, lon: -7.9322, tracks: 4, manhours: 80 },
  { name: 'Évora', code: 'EVO', lat: 38.5714, lon: -7.9092, tracks: 3, manhours: 60 },
  { name: 'Setúbal', code: 'SET', lat: 38.5244, lon: -8.8882, tracks: 4, manhours: 80 },
  { name: 'Guimarães', code: 'GUI', lat: 41.4433, lon: -8.2919, tracks: 3, manhours: 60 },
  { name: 'Viseu', code: 'VIS', lat: 40.6566, lon: -7.9124, tracks: 3, manhours: 60 },
  { name: 'Leiria', code: 'LEI', lat: 39.7436, lon: -8.8071, tracks: 3, manhours: 60 },
];

const TRAIN_PREFIXES = {
  'Metro Series 2200': 'UTE-2200',
  'Metro Series 2400': 'UTE-2400',
  'Intercity Series 3400': 'UTE-3400',
  'Regional Series 3500': 'UME-3500',
  'Urban Series 4000': 'UTE-4000',
};

const SERVICE_ROUTES = [
  // Intercity routes
  { code: 'IC', origin: 'Lisboa - Santa Apolónia', destination: 'Porto - Campanhã', distance: 336, type: 'intercity' },
  { code: 'IC', origin: 'Porto - Campanhã', destination: 'Lisboa - Santa Apolónia', distance: 336, type: 'intercity' },
  { code: 'IC', origin: 'Lisboa - Santa Apolónia', destination: 'Faro', distance: 309, type: 'intercity' },
  { code: 'IC', origin: 'Faro', destination: 'Lisboa - Santa Apolónia', distance: 309, type: 'intercity' },
  { code: 'IC', origin: 'Porto - Campanhã', destination: 'Braga', distance: 65, type: 'intercity' },
  { code: 'IC', origin: 'Braga', destination: 'Porto - Campanhã', distance: 65, type: 'intercity' },
  // Regional routes
  { code: 'R', origin: 'Lisboa - Entrecampos', destination: 'Coimbra B', distance: 199, type: 'regional' },
  { code: 'R', origin: 'Coimbra B', destination: 'Lisboa - Entrecampos', distance: 199, type: 'regional' },
  { code: 'R', origin: 'Porto - São Bento', destination: 'Aveiro', distance: 75, type: 'regional' },
  { code: 'R', origin: 'Aveiro', destination: 'Porto - São Bento', distance: 75, type: 'regional' },
  { code: 'R', origin: 'Lisboa - Santa Apolónia', destination: 'Setúbal', distance: 50, type: 'regional' },
  { code: 'R', origin: 'Setúbal', destination: 'Lisboa - Santa Apolónia', distance: 50, type: 'regional' },
  { code: 'R', origin: 'Porto - Campanhã', destination: 'Guimarães', distance: 60, type: 'regional' },
  { code: 'R', origin: 'Guimarães', destination: 'Porto - Campanhã', distance: 60, type: 'regional' },
  { code: 'R', origin: 'Coimbra B', destination: 'Leiria', distance: 75, type: 'regional' },
  { code: 'R', origin: 'Leiria', destination: 'Coimbra B', distance: 75, type: 'regional' },
  // Urban routes
  { code: 'U', origin: 'Lisboa - Entrecampos', destination: 'Lisboa - Santa Apolónia', distance: 5, type: 'regional' },
  { code: 'U', origin: 'Porto - Campanhã', destination: 'Porto - São Bento', distance: 3, type: 'regional' },
];

// =============================================================================
// Helper Functions
// =============================================================================

function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function randomFloat(min: number, max: number, decimals: number = 2): number {
  const value = Math.random() * (max - min) + min;
  return Number(value.toFixed(decimals));
}

function randomChoice<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

function formatTime(hours: number, minutes: number): string {
  return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:00`;
}

function addMinutes(time: string, minutes: number): string {
  const [h, m] = time.split(':').map(Number);
  const totalMinutes = h * 60 + m + minutes;
  const newH = Math.floor(totalMinutes / 60) % 24;
  const newM = totalMinutes % 60;
  return formatTime(newH, newM);

/**
 * MMS - Database Migration Script
 *
 * Run with: bun run db:migrate
 */

import postgres from 'postgres';

const connectionString = process.env.DATABASE_URL || 'postgresql://mms:mms@localhost:5432/mms';

const sql = postgres(connectionString);

async function migrate() {
  console.log('Running MMS database migrations...');

  try {
    // Create extension for UUID generation
    await sql`CREATE EXTENSION IF NOT EXISTS "pgcrypto"`;

    // Create fleets table
    await sql`
      CREATE TABLE IF NOT EXISTS fleets (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        name VARCHAR(100) NOT NULL,
        manufacturer VARCHAR(50),
        pm1_interval_km INTEGER NOT NULL,
        pm2_interval_km INTEGER NOT NULL,
        hm_interval_km INTEGER NOT NULL,
        created_at TIMESTAMP DEFAULT NOW()
      )
    `;
    console.log('  ✓ fleets table');

    // Create depots table
    await sql`
      CREATE TABLE IF NOT EXISTS depots (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        name VARCHAR(100) NOT NULL,
        code VARCHAR(10) UNIQUE NOT NULL,
        latitude DECIMAL(10, 6),
        longitude DECIMAL(10, 6),
        capacity_tracks INTEGER DEFAULT 5,
        capacity_manhours INTEGER DEFAULT 80,
        created_at TIMESTAMP DEFAULT NOW()
      )
    `;
    console.log('  ✓ depots table');

    // Create trains table
    await sql`
      CREATE TABLE IF NOT EXISTS trains (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        train_id VARCHAR(20) UNIQUE NOT NULL,
        fleet_id UUID REFERENCES fleets(id),
        base_depot_id UUID REFERENCES depots(id),
        current_km INTEGER DEFAULT 0,
        target_km INTEGER DEFAULT 0,
        fitness_status VARCHAR(10) DEFAULT 'fit' CHECK (fitness_status IN ('fit', 'unfit')),
        last_maintenance_date DATE,
        next_maintenance_km INTEGER,
        latitude DECIMAL(10, 6),
        longitude DECIMAL(10, 6),
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      )
    `;
    console.log('  ✓ trains table');

    // Create services table
    await sql`
      CREATE TABLE IF NOT EXISTS services (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        service_code VARCHAR(20) UNIQUE NOT NULL,
        origin VARCHAR(100) NOT NULL,
        destination VARCHAR(100) NOT NULL,
        distance_km INTEGER NOT NULL,
        departure_time TIME NOT NULL,
        arrival_time TIME NOT NULL,
        service_type VARCHAR(20) DEFAULT 'regional',
        created_at TIMESTAMP DEFAULT NOW()
      )
    `;
    console.log('  ✓ services table');

    // Create allocations table
    await sql`
      CREATE TABLE IF NOT EXISTS allocations (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        service_id UUID REFERENCES services(id),
        train_id UUID REFERENCES trains(id),
        allocation_date DATE NOT NULL,
        status VARCHAR(20) DEFAULT 'pending' CHECK (status IN ('pending', 'confirmed', 'completed', 'cancelled')),
        score INTEGER,
        justifications JSONB,
        created_by VARCHAR(100),
        created_at TIMESTAMP DEFAULT NOW(),
        UNIQUE(service_id, allocation_date)
      )
    `;
    console.log('  ✓ allocations table');

    // Create mileage_history table
    await sql`
      CREATE TABLE IF NOT EXISTS mileage_history (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        train_id UUID REFERENCES trains(id),
        recorded_date DATE NOT NULL,
        km_value INTEGER NOT NULL,
        created_at TIMESTAMP DEFAULT NOW()
      )
    `;
    console.log('  ✓ mileage_history table');

    // Create maintenance_schedules table
    await sql`
      CREATE TABLE IF NOT EXISTS maintenance_schedules (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        train_id UUID REFERENCES trains(id),
        depot_id UUID REFERENCES depots(id),
        maintenance_type VARCHAR(10) CHECK (maintenance_type IN ('PM1', 'PM2', 'HM', 'OVH')),
        scheduled_date DATE NOT NULL,
        duration_days INTEGER DEFAULT 1,
        status VARCHAR(20) DEFAULT 'scheduled' CHECK (status IN ('scheduled', 'in_progress', 'completed', 'cancelled')),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `;
    console.log('  ✓ maintenance_schedules table');

    // Create indexes
    await sql`CREATE INDEX IF NOT EXISTS idx_trains_fleet ON trains(fleet_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_trains_depot ON trains(base_depot_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_allocations_date ON allocations(allocation_date)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_allocations_status ON allocations(status)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_mileage_train_date ON mileage_history(train_id, recorded_date)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_maintenance_train ON maintenance_schedules(train_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_maintenance_depot ON maintenance_schedules(depot_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_maintenance_date ON maintenance_schedules(scheduled_date)`;
    console.log('  ✓ indexes created');

    console.log('\n✅ All migrations completed successfully!');
  } catch (error) {
    console.error('Migration failed:', error);
    process.exit(1);
  } finally {
    await sql.end();
  }
}

migrate();
